export class ADRBuilder {
    /**
     * Generates a structured ADR markdown file content.
     */
    static build(data) {
        return `
# ADR ${data.id}: ${data.title}

- **Status**: ${data.status}
- **Date**: ${new Date().toISOString().split('T')[0]}

## Context
${data.context}

## Decision
${data.decision}

## Consequences
${data.consequences}

---
*Generated by ngxsmk-migrate ADR Engine*
`;
    }
}
